import React, { useState, useRef, useCallback } from "react";

// ═══ DEVICE TYPES ═══
const DEVICE_TYPES = {
  switch: {
    label: "Switch", color: "#1d4ed8", bg: "#eff6ff",
    icon: <><rect x="2" y="2" width="20" height="8" rx="2"/><rect x="2" y="14" width="20" height="8" rx="2"/><line x1="6" y1="6" x2="6.01" y2="6"/><line x1="6" y1="18" x2="6.01" y2="18"/></>,
    models: [
      { name:"Cisco 2960-24TT", ports:"24 FE + 2 GE", ios:"15.0(2)SE4", desc:"Layer 2 — Small networks" },
      { name:"Cisco 2960-48TT", ports:"48 FE + 2 GE", ios:"15.0(2)SE4", desc:"Layer 2 — Medium offices" },
      { name:"Cisco 3560-24PS", ports:"24 FE PoE + 2 GE", ios:"12.2(55)SE", desc:"Layer 3 — PoE support" },
      { name:"Cisco 3750-48TS", ports:"48 GE + 4 SFP", ios:"12.2(55)SE", desc:"Layer 3 — StackWise" },
      { name:"Cisco 9200-24P", ports:"24 GE PoE + 4 SFP", ios:"17.x", desc:"Layer 3 — SD-Access" },
    ],
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2","GigabitEthernet0/3"],
  },
  router: {
    label: "Router", color: "#15803d", bg: "#f0fdf4",
    icon: <><path d="M5 12.55a11 11 0 0 1 14.08 0"/><path d="M1.42 9a16 16 0 0 1 21.16 0"/><path d="M8.53 16.11a6 6 0 0 1 6.95 0"/><line x1="12" y1="20" x2="12.01" y2="20"/></>,
    models: [
      { name:"Cisco 1941", ports:"2 GE + 2 WAN", ios:"15.1(4)M4", desc:"Small business router" },
      { name:"Cisco 2901", ports:"2 GE + Modules", ios:"15.1(4)M4", desc:"Branch office router" },
      { name:"Cisco 2911", ports:"3 GE + 4 Slots", ios:"15.1(4)M4", desc:"CCNA/CCNP lab router" },
      { name:"Cisco 4321", ports:"2 GE + 2 SFP", ios:"16.x", desc:"Enterprise router" },
      { name:"Cisco ISR 1100", ports:"4 GE + LTE", ios:"17.x", desc:"Next-gen ISR + WiFi" },
    ],
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","Serial0/0/0","Serial0/0/1"],
  },
  firewall: {
    label: "Firewall", color: "#b91c1c", bg: "#fef2f2",
    icon: <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/>,
    models: [
      { name:"Cisco ASA 5505", ports:"8 FE", ios:"ASA 9.2", desc:"Small business firewall" },
      { name:"Cisco ASA 5506-X", ports:"8 GE + 1 Mgmt", ios:"ASA 9.8", desc:"FirePOWER IPS support" },
      { name:"Cisco ASA 5516-X", ports:"8 GE + 2 SFP", ios:"ASA 9.8", desc:"Medium enterprise" },
      { name:"Cisco FTD 1010", ports:"8 GE", ios:"FTD 7.x", desc:"Next-gen firewall" },
    ],
    interfaces: ["GigabitEthernet0/0","GigabitEthernet0/1","GigabitEthernet0/2"],
  },
  pc: {
    label: "PC", color: "#374151", bg: "#f9fafb",
    icon: <><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></>,
    models: [
      { name:"PC (Windows)", ports:"1 NIC", ios:"Windows 10/11", desc:"End user workstation" },
      { name:"PC (Linux)", ports:"1 NIC", ios:"Ubuntu 22.04", desc:"Linux workstation" },
      { name:"Laptop", ports:"1 NIC + WiFi", ios:"Windows 11", desc:"Mobile workstation" },
    ],
    interfaces: ["FastEthernet0"],
  },
  server: {
    label: "Server", color: "#7c3aed", bg: "#fdf4ff",
    icon: <><rect x="2" y="2" width="20" height="8" rx="2"/><rect x="2" y="14" width="20" height="8" rx="2"/><line x1="6" y1="6" x2="6.01" y2="6"/><line x1="6" y1="18" x2="6.01" y2="18"/><line x1="10" y1="6" x2="10.01" y2="6"/><line x1="10" y1="18" x2="10.01" y2="18"/></>,
    models: [
      { name:"DHCP Server", ports:"2 GE", ios:"Server IOS", desc:"Dynamic IP assignment" },
      { name:"DNS Server", ports:"2 GE", ios:"Server IOS", desc:"Domain name resolution" },
      { name:"Web Server", ports:"2 GE", ios:"Server IOS", desc:"HTTP/HTTPS services" },
      { name:"File Server", ports:"2 GE", ios:"Server IOS", desc:"File sharing services" },
    ],
    interfaces: ["FastEthernet0","FastEthernet1"],
  },
};

// ═══ SVG ICON ═══
const DevIcon = ({ type, size=24, color }) => {
  const info = DEVICE_TYPES[type];
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color||info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      {info.icon}
    </svg>
  );
};

// ═══ TERMINAL ═══
const lineColors = { header:"#60a5fa", success:"#34d399", warn:"#fbbf24", error:"#f87171", info:"#a78bfa", muted:"#475569", text:"#e2e8f0" };

const DeviceTerminal = ({ device, onClose }) => {
  const [input, setInput] = useState("");
  const [lines, setLines] = useState([
    { t:"info", v:`Connected to ${device.name} (${device.model})` },
    { t:"muted", v:"Type ? for help." },
    { t:"muted", v:"" },
  ]);
  const [mode, setMode] = useState("privileged");
  const [hostname, setHostname] = useState(device.name);
  const [currentIface, setCurrentIface] = useState(null);
  const [history, setHistory] = useState([]);
  const [histIdx, setHistIdx] = useState(-1);
  const termRef = useRef(null);
  const inputRef = useRef(null);

  const modeMap = { user:`${hostname}>`, privileged:`${hostname}#`, config:`${hostname}(config)#`, interface:`${hostname}(config-if)#` };
  const prompt = modeMap[mode] || `${hostname}#`;

  const addLines = (newLines) => {
    setLines(prev => [...prev, ...newLines]);
    setTimeout(() => { if(termRef.current) termRef.current.scrollTop = termRef.current.scrollHeight; }, 30);
  };

  const handleKey = (e) => {
    if (e.key === "Enter") {
      const cmd = input.trim();
      setInput(""); setHistIdx(-1);
      if (cmd) setHistory(prev => [cmd, ...prev]);
      addLines([{ t:"prompt-line", prompt, cmd }]);
      processCmd(cmd);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      const i = histIdx + 1;
      if (i < history.length) { setHistIdx(i); setInput(history[i]); }
    } else if (e.key === "ArrowDown") {
      e.preventDefault();
      const i = histIdx - 1;
      if (i < 0) { setHistIdx(-1); setInput(""); }
      else { setHistIdx(i); setInput(history[i]); }
    }
  };

  const processCmd = (raw) => {
    const cmd = raw.toLowerCase().trim();
    const parts = cmd.split(/\s+/);
    const ts = () => { const n = new Date(); return `*${n.toLocaleDateString("en-US",{month:"short",day:"2-digit",year:"numeric"})} ${n.toTimeString().slice(0,8)}`; };

    if (!cmd) return;
    if (cmd === "clear" || cmd === "cls") { setLines([]); return; }

    if (cmd === "?" || cmd === "help") {
      addLines([
        { t:"header", v:"Available Commands:" },
        { t:"info", v:"  enable                 Enter privileged mode" },
        { t:"info", v:"  configure terminal     Enter config mode" },
        { t:"info", v:"  hostname <name>        Set hostname" },
        { t:"info", v:"  interface <name>       Enter interface config" },
        { t:"info", v:"  ip address <ip> <mask> Assign IP" },
        { t:"info", v:"  no shutdown            Enable interface" },
        { t:"info", v:"  shutdown               Disable interface" },
        { t:"info", v:"  show ip interface brief" },
        { t:"info", v:"  show running-config" },
        { t:"info", v:"  write memory           Save config" },
        { t:"info", v:"  end / exit             Change mode" },
      ]);
      return;
    }

    if (cmd === "enable" || cmd === "en") {
      if (mode === "user") { setMode("privileged"); addLines([{ t:"success", v:"Entering privileged EXEC mode..." }]); }
      else addLines([{ t:"warn", v:"Already in privileged mode." }]);
      return;
    }
    if (cmd === "disable") { setMode("user"); return; }

    if (cmd === "configure terminal" || cmd === "conf t") {
      if (mode !== "privileged") { addLines([{ t:"error", v:"% Must be in privileged mode." }]); return; }
      setMode("config");
      addLines([{ t:"info", v:"Enter configuration commands, one per line. End with CNTL/Z." }]);
      return;
    }

    if (cmd === "end" || cmd === "exit") {
      if (mode === "interface") { setMode("config"); setCurrentIface(null); }
      else if (mode === "config") { setMode("privileged"); addLines([{ t:"success", v:`${ts()}: %SYS-5-CONFIG_I: Configured from console` }]); }
      else if (mode === "privileged") setMode("user");
      return;
    }

    if (parts[0] === "hostname" && parts[1]) {
      if (mode !== "config") { addLines([{ t:"error", v:"% Must be in config mode." }]); return; }
      setHostname(parts[1]);
      addLines([{ t:"success", v:`Hostname changed to '${parts[1]}'` }]);
      return;
    }

    if ((parts[0] === "interface" || parts[0] === "int") && parts[1]) {
      if (mode !== "config") { addLines([{ t:"error", v:"% Must be in config mode." }]); return; }
      const ifName = parts.slice(1).join(" ").replace(/^gi/i,"GigabitEthernet").replace(/^fa/i,"FastEthernet").replace(/^se/i,"Serial");
      setCurrentIface(ifName);
      setMode("interface");
      addLines([{ t:"info", v:`Configuring interface ${ifName}` }]);
      return;
    }

    if (parts[0] === "ip" && parts[1] === "address" && parts[2] && parts[3]) {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([{ t:"success", v:`IP address ${parts[2]} ${parts[3]} assigned to ${currentIface}` }]);
      return;
    }

    if (cmd === "no shutdown" || cmd === "no shut") {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([
        { t:"success", v:`${ts()}: %LINK-3-UPDOWN: Interface ${currentIface}, changed state to up` },
        { t:"success", v:`${ts()}: %LINEPROTO-5-UPDOWN: Line protocol changed state to up` },
      ]);
      return;
    }

    if (cmd === "shutdown" || cmd === "shut") {
      if (mode !== "interface") { addLines([{ t:"error", v:"% Must be in interface config mode." }]); return; }
      addLines([{ t:"warn", v:`${ts()}: %LINK-5-CHANGED: Interface ${currentIface}, changed state to administratively down` }]);
      return;
    }

    if (cmd === "show ip interface brief" || cmd === "sh ip int br") {
      const ifaces = DEVICE_TYPES[device.type]?.interfaces || [];
      addLines([{ t:"header", v:"Interface              IP-Address      OK? Method Status                Protocol" }]);
      ifaces.forEach((iface, i) => {
        const short = iface.replace("GigabitEthernet","Gi").replace("FastEthernet","Fa").replace("Serial","Se");
        addLines([{ t: i===0?"success":"warn", v:`${short.padEnd(23)}${"unassigned".padEnd(16)}NO  unset  ${"down".padEnd(22)}down` }]);
      });
      return;
    }

    if (cmd === "show running-config" || cmd === "sh run") {
      addLines([
        { t:"info", v:"Building configuration..." },
        { t:"header", v:"Current configuration:" },
        { t:"muted", v:"!" },
        { t:"text", v:`hostname ${hostname}` },
        { t:"muted", v:"!" },
        { t:"text", v:"end" },
      ]);
      return;
    }

    if (cmd === "write memory" || cmd === "wr") {
      addLines([{ t:"info", v:"Building configuration..." }, { t:"success", v:"[OK]" }]);
      return;
    }

    addLines([{ t:"error", v:`% Unrecognized command: '${raw}'. Type ? for help.` }]);
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"#00000088", backdropFilter:"blur(4px)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:300 }}>
      <div style={{ width:640, height:500, background:"#0f172a", borderRadius:14, display:"flex", flexDirection:"column", boxShadow:"0 24px 60px #00000055", overflow:"hidden" }}>
        <div style={{ background:"#1e293b", padding:"10px 16px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ display:"flex", gap:6 }}>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#ef4444" }}/>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#f59e0b" }}/>
              <div style={{ width:11, height:11, borderRadius:"50%", background:"#10b981" }}/>
            </div>
            <DevIcon type={device.type} size={16} color="#64748b" />
            <span style={{ fontSize:12, color:"#64748b", fontFamily:"monospace" }}>{device.name} ({device.model})</span>
          </div>
          <button onClick={onClose} style={{ background:"#334155", border:"none", color:"#94a3b8", width:24, height:24, borderRadius:4, cursor:"pointer", fontSize:14 }}>x</button>
        </div>
        <div ref={termRef} style={{ flex:1, overflowY:"auto", padding:"14px 18px", fontFamily:"monospace", fontSize:13, lineHeight:1.7, cursor:"text" }} onClick={()=>inputRef.current?.focus()}>
          {lines.map((line, i) => {
            if (line.t === "prompt-line") return (
              <div key={i}><span style={{ color:"#10b981", fontWeight:700 }}>{line.prompt} </span><span style={{ color:"#f8fafc" }}>{line.cmd}</span></div>
            );
            return <div key={i} style={{ color: lineColors[line.t]||lineColors.text }}>{line.v||"\u00A0"}</div>;
          })}
          <div style={{ display:"flex", alignItems:"center" }}>
            <span style={{ color:"#10b981", fontWeight:700, marginRight:6 }}>{prompt}</span>
            <input ref={inputRef} value={input} onChange={e=>setInput(e.target.value)} onKeyDown={handleKey} autoFocus
              style={{ background:"transparent", border:"none", outline:"none", color:"#f8fafc", fontFamily:"monospace", fontSize:13, flex:1 }}
              spellCheck={false} autoComplete="off" />
          </div>
        </div>
        <div style={{ background:"#1e293b", padding:"5px 16px", fontSize:10, color:"#475569", display:"flex", gap:16 }}>
          <span>Up/Down: History</span><span>?: Help</span><span>clear: Clear screen</span>
        </div>
      </div>
    </div>
  );
};

// ═══ CONFIG PANEL ═══
const Field = ({ label, value, onChange, placeholder, type="text" }) => (
  <div style={{ marginBottom:12 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:4 }}>{label}</div>
    <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{ width:"100%", padding:"8px 10px", border:"1px solid #e5e7eb", borderRadius:6, fontSize:12, outline:"none", fontFamily:"monospace", boxSizing:"border-box", background:"#f9fafb" }} />
  </div>
);
const Sel = ({ label, value, onChange, options }) => (
  <div style={{ marginBottom:12 }}>
    <div style={{ fontSize:11, fontWeight:600, color:"#374151", marginBottom:4 }}>{label}</div>
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{ width:"100%", padding:"8px 10px", border:"1px solid #e5e7eb", borderRadius:6, fontSize:12, outline:"none", boxSizing:"border-box", background:"#f9fafb" }}>
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
  </div>
);

const ConfigPanel = ({ device, onClose }) => {
  const [action, setAction] = useState("ip");
  const [ip, setIp] = useState("");
  const [mask, setMask] = useState("255.255.255.0");
  const [iface, setIface] = useState(DEVICE_TYPES[device.type]?.interfaces[0] || "");
  const [portAction, setPortAction] = useState("enable");
  const [vlanId, setVlanId] = useState("");
  const [vlanName, setVlanName] = useState("");
  const [newHostname, setNewHostname] = useState("");
  const [routeNet, setRouteNet] = useState("");
  const [routeMask, setRouteMask] = useState("255.255.255.0");
  const [routeGw, setRouteGw] = useState("");
  const [termLines, setTermLines] = useState([
    { t:"info", v:`Device: ${device.name} (${device.model})` },
    { t:"muted", v:"Ready for configuration." },
  ]);

  const addCmd = (cmds) => {
    const newLines = cmds.map(c => ({ t:"prompt-line", prompt:`${device.name}#`, cmd:c }));
    setTermLines(prev => [...prev, ...newLines]);
  };
  const addOut = (lines) => setTermLines(prev => [...prev, ...lines]);

  const actions = [
    { id:"ip", label:"Set IP", icon:<><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></> },
    { id:"port", label:"Port", icon:<><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></> },
    { id:"vlan", label:"VLAN", icon:<><polygon points="12 2 2 7 12 12 22 7 12 2"/><polyline points="2 17 12 22 22 17"/></> },
    { id:"hostname", label:"Hostname", icon:<><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></> },
    { id:"route", label:"Route", icon:<><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></> },
    { id:"save", label:"Save", icon:<><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/></> },
    { id:"show", label:"Show", icon:<><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></> },
  ];

  const ifaceOptions = (DEVICE_TYPES[device.type]?.interfaces||[]).map(i=>({value:i,label:i.replace("GigabitEthernet","Gi").replace("FastEthernet","Fa")}));

  const apply = () => {
    if (action === "ip") {
      if (!ip) return;
      const cmds = ["configure terminal", `interface ${iface}`, `ip address ${ip} ${mask}`, "no shutdown", "end"];
      addCmd(cmds);
      addOut([{ t:"success", v:`IP ${ip} ${mask} assigned to ${iface}` }]);
    } else if (action === "port") {
      const cmd = portAction === "enable" ? "no shutdown" : "shutdown";
      const cmds = ["configure terminal", `interface ${iface}`, cmd, "end"];
      addCmd(cmds);
      addOut([{ t: portAction==="enable"?"success":"warn", v:`Interface ${iface} ${portAction==="enable"?"enabled":"disabled"}` }]);
    } else if (action === "vlan") {
      if (!vlanId) return;
      const cmds = ["configure terminal", `vlan ${vlanId}`, vlanName?`name ${vlanName}`:"", "exit", `interface ${iface}`, "switchport mode access", `switchport access vlan ${vlanId}`, "end"].filter(Boolean);
      addCmd(cmds);
      addOut([{ t:"success", v:`VLAN ${vlanId} created and assigned to ${iface}` }]);
    } else if (action === "hostname") {
      if (!newHostname) return;
      const cmds = ["configure terminal", `hostname ${newHostname}`, "end"];
      addCmd(cmds);
      addOut([{ t:"success", v:`Hostname changed to ${newHostname}` }]);
    } else if (action === "route") {
      if (!routeNet||!routeGw) return;
      const cmds = ["configure terminal", `ip route ${routeNet} ${routeMask} ${routeGw}`, "end"];
      addCmd(cmds);
      addOut([{ t:"success", v:`Route ${routeNet} via ${routeGw} added` }]);
    } else if (action === "save") {
      addCmd(["write memory"]);
      addOut([{ t:"success", v:"[OK] Configuration saved." }]);
    } else if (action === "show") {
      addCmd(["show ip interface brief"]);
      addOut([
        { t:"header", v:"Interface              IP-Address      OK? Method Status" },
        ...((DEVICE_TYPES[device.type]?.interfaces||[]).map((f,i) => ({
          t: i===0?"success":"warn",
          v:`${f.replace("GigabitEthernet","Gi").replace("FastEthernet","Fa").padEnd(23)}${"unassigned".padEnd(16)}NO  unset  down`
        })))
      ]);
    }
  };

  const info = DEVICE_TYPES[device.type];

  return (
    <div style={{ position:"fixed", inset:0, background:"#00000088", backdropFilter:"blur(4px)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:300 }}>
      <div style={{ width:780, height:540, background:"#fff", borderRadius:16, display:"flex", overflow:"hidden", boxShadow:"0 24px 60px #00000030" }}>

        {/* LEFT — CONFIG */}
        <div style={{ width:300, borderRight:"1px solid #e5e7eb", display:"flex", flexDirection:"column" }}>
          <div style={{ padding:"16px", borderBottom:"1px solid #e5e7eb", display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:36, height:36, background:info.bg, borderRadius:8, display:"flex", alignItems:"center", justifyContent:"center" }}>
              <DevIcon type={device.type} size={20} />
            </div>
            <div>
              <div style={{ fontSize:13, fontWeight:700, color:"#111827" }}>{device.name}</div>
              <div style={{ fontSize:10, color:"#9ca3af" }}>{device.model}</div>
            </div>
            <button onClick={onClose} style={{ marginLeft:"auto", background:"#f3f4f6", border:"none", borderRadius:6, width:26, height:26, cursor:"pointer", fontSize:14, color:"#6b7280" }}>x</button>
          </div>

          {/* ACTION TABS */}
          <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:4, padding:"10px" }}>
            {actions.map(a => (
              <button key={a.id} onClick={()=>setAction(a.id)} style={{ background: action===a.id ? info.color : "#f8fafc", border:`1px solid ${action===a.id ? info.color : "#e5e7eb"}`, borderRadius:8, padding:"8px 4px", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:3 }}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={action===a.id?"#fff":info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{a.icon}</svg>
                <span style={{ fontSize:9, fontWeight:700, color: action===a.id?"#fff":info.color }}>{a.label}</span>
              </button>
            ))}
          </div>

          {/* FORM */}
          <div style={{ flex:1, padding:"10px 14px", overflowY:"auto" }}>
            {action === "ip" && <>
              <Sel label="Interface" value={iface} onChange={setIface} options={ifaceOptions} />
              <Field label="IP Address" value={ip} onChange={setIp} placeholder="192.168.1.1" />
              <Field label="Subnet Mask" value={mask} onChange={setMask} placeholder="255.255.255.0" />
            </>}
            {action === "port" && <>
              <Sel label="Interface" value={iface} onChange={setIface} options={ifaceOptions} />
              <Sel label="Action" value={portAction} onChange={setPortAction} options={[{value:"enable",label:"Enable (no shutdown)"},{value:"disable",label:"Disable (shutdown)"}]} />
            </>}
            {action === "vlan" && <>
              <Field label="VLAN ID" value={vlanId} onChange={setVlanId} placeholder="e.g. 10" />
              <Field label="VLAN Name" value={vlanName} onChange={setVlanName} placeholder="e.g. Management" />
              <Sel label="Interface" value={iface} onChange={setIface} options={ifaceOptions} />
            </>}
            {action === "hostname" && <Field label="New Hostname" value={newHostname} onChange={setNewHostname} placeholder="e.g. CoreSwitch" />}
            {action === "route" && <>
              <Field label="Network" value={routeNet} onChange={setRouteNet} placeholder="192.168.2.0" />
              <Field label="Mask" value={routeMask} onChange={setRouteMask} placeholder="255.255.255.0" />
              <Field label="Next Hop" value={routeGw} onChange={setRouteGw} placeholder="192.168.1.254" />
            </>}
            {action === "save" && <div style={{ fontSize:12, color:"#6b7280", lineHeight:1.6 }}>Save running configuration to NVRAM startup-config.</div>}
            {action === "show" && <div style={{ fontSize:12, color:"#6b7280", lineHeight:1.6 }}>Show interface status and IP assignments.</div>}
          </div>

          <div style={{ padding:"12px 14px", borderTop:"1px solid #e5e7eb" }}>
            <button onClick={apply} style={{ width:"100%", background:info.color, border:"none", color:"#fff", padding:"10px", borderRadius:8, cursor:"pointer", fontSize:13, fontWeight:700 }}>
              Apply
            </button>
          </div>
        </div>

        {/* RIGHT — TERMINAL */}
        <div style={{ flex:1, background:"#0f172a", display:"flex", flexDirection:"column" }}>
          <div style={{ background:"#1e293b", padding:"10px 16px", display:"flex", alignItems:"center", gap:8 }}>
            <div style={{ display:"flex", gap:6 }}>
              <div style={{ width:10, height:10, borderRadius:"50%", background:"#ef4444" }}/>
              <div style={{ width:10, height:10, borderRadius:"50%", background:"#f59e0b" }}/>
              <div style={{ width:10, height:10, borderRadius:"50%", background:"#10b981" }}/>
            </div>
            <span style={{ fontSize:11, color:"#64748b", fontFamily:"monospace" }}>Terminal — {device.name}</span>
          </div>
          <div style={{ flex:1, overflowY:"auto", padding:"14px 18px", fontFamily:"monospace", fontSize:12, lineHeight:1.8 }}>
            {termLines.map((line, i) => {
              if (line.t === "prompt-line") return (
                <div key={i}><span style={{ color:"#10b981", fontWeight:700 }}>{line.prompt} </span><span style={{ color:"#f8fafc" }}>{line.cmd}</span></div>
              );
              return <div key={i} style={{ color: lineColors[line.t]||lineColors.text }}>{line.v||"\u00A0"}</div>;
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

// ═══ TOPOLOGY ═══
const Topology = () => {
  const [devices, setDevices] = useState([
    { id:"sw1", type:"switch", name:"Switch1", model:"Cisco 2960-24TT", x:300, y:200 },
    { id:"rt1", type:"router", name:"Router1", model:"Cisco 2911", x:520, y:180 },
    { id:"pc1", type:"pc", name:"PC1", model:"PC (Windows)", x:160, y:340 },
    { id:"pc2", type:"pc", name:"PC2", model:"PC (Windows)", x:320, y:360 },
  ]);
  const [links, setLinks] = useState([
    { id:"l1", from:"pc1", to:"sw1" },
    { id:"l2", from:"pc2", to:"sw1" },
    { id:"l3", from:"sw1", to:"rt1" },
  ]);
  const [dragging, setDragging] = useState(null);
  const [offset, setOffset] = useState({x:0,y:0});
  const [tool, setTool] = useState("select");
  const [linking, setLinking] = useState(null);
  const [configDevice, setConfigDevice] = useState(null);
  const [termDevice, setTermDevice] = useState(null);
  const [selected, setSelected] = useState(null);
  const canvasRef = useRef(null);
  const counter = useRef(20);

  const getCenter = d => ({ x: d.x+40, y: d.y+40 });

  const handleMouseDown = (e, dev) => {
    e.stopPropagation();
    if (tool === "link") {
      if (!linking) setLinking(dev.id);
      else if (linking !== dev.id) {
        const exists = links.find(l=>(l.from===linking&&l.to===dev.id)||(l.from===dev.id&&l.to===linking));
        if (!exists) setLinks(prev=>[...prev,{id:`l${Date.now()}`,from:linking,to:dev.id}]);
        setLinking(null);
      }
      return;
    }
    if (tool === "delete") {
      setDevices(prev=>prev.filter(d=>d.id!==dev.id));
      setLinks(prev=>prev.filter(l=>l.from!==dev.id&&l.to!==dev.id));
      return;
    }
    setDragging(dev.id);
    setOffset({x:e.clientX-dev.x, y:e.clientY-dev.y});
    setSelected(dev.id);
  };

  const handleMouseMove = useCallback((e) => {
    if (!dragging) return;
    const canvas = canvasRef.current?.getBoundingClientRect();
    if (!canvas) return;
    setDevices(prev=>prev.map(d=>d.id===dragging?{...d,x:Math.max(0,Math.min(e.clientX-offset.x,canvas.width-80)),y:Math.max(0,Math.min(e.clientY-offset.y,canvas.height-80))}:d));
  }, [dragging, offset]);

  const addDevice = (type, model) => {
    counter.current++;
    const info = DEVICE_TYPES[type];
    setDevices(prev=>[...prev,{id:`${type}${counter.current}`,type,name:`${info.label}${counter.current}`,model:model.name,x:180+Math.random()*240,y:140+Math.random()*180}]);
  };

  return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", background:"#f8fafc", overflow:"hidden" }}>

      {/* TOOLBAR */}
      <div style={{ background:"#fff", borderBottom:"1px solid #e5e7eb", padding:"8px 16px", display:"flex", alignItems:"center", gap:6, flexWrap:"wrap" }}>
        <span style={{ fontSize:10, fontWeight:700, color:"#9ca3af", marginRight:4 }}>ADD DEVICE:</span>
        {Object.entries(DEVICE_TYPES).map(([type, info]) => (
          <div key={type} style={{ position:"relative" }} className="device-dropdown">
            <button style={{ background:`${info.color}12`, border:`1px solid ${info.color}40`, color:info.color, padding:"5px 10px", borderRadius:6, cursor:"pointer", fontSize:11, fontWeight:700, display:"flex", alignItems:"center", gap:5 }}
              onClick={() => addDevice(type, info.models[0])}>
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
              {info.label}
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="6 9 12 15 18 9"/></svg>
            </button>
          </div>
        ))}

        <div style={{ width:1, background:"#e5e7eb", height:24, margin:"0 6px" }}/>
        <span style={{ fontSize:10, fontWeight:700, color:"#9ca3af", marginRight:4 }}>TOOL:</span>
        {[
          { id:"select", label:"Select" },
          { id:"link", label:"Link" },
          { id:"delete", label:"Delete" },
        ].map(t => (
          <button key={t.id} onClick={()=>{setTool(t.id);setLinking(null);}} style={{ background:tool===t.id?"#1d4ed8":"#f3f4f6", border:"1px solid", borderColor:tool===t.id?"#1d4ed8":"#e5e7eb", color:tool===t.id?"#fff":"#374151", padding:"5px 12px", borderRadius:6, cursor:"pointer", fontSize:11, fontWeight:700 }}>
            {t.label}
          </button>
        ))}
        {linking && <div style={{ background:"#fef3c7", border:"1px solid #fde68a", color:"#92400e", padding:"4px 12px", borderRadius:6, fontSize:11, fontWeight:600 }}>Click device to link...</div>}
      </div>

      <div style={{ flex:1, display:"flex", overflow:"hidden" }}>
        {/* CANVAS */}
        <div ref={canvasRef} style={{ flex:1, position:"relative", background:"#f1f5f9", backgroundImage:"radial-gradient(#cbd5e1 1px, transparent 1px)", backgroundSize:"24px 24px", cursor:tool==="link"?"crosshair":tool==="delete"?"not-allowed":"default", overflow:"hidden" }}
          onMouseMove={handleMouseMove} onMouseUp={()=>setDragging(null)}
          onClick={()=>{ if(tool==="select") setSelected(null); }}>

          <svg style={{ position:"absolute", inset:0, width:"100%", height:"100%", pointerEvents:"none" }}>
            {links.map(link => {
              const from = devices.find(d=>d.id===link.from);
              const to = devices.find(d=>d.id===link.to);
              if (!from||!to) return null;
              const fc=getCenter(from); const tc=getCenter(to);
              const mx=(fc.x+tc.x)/2; const my=(fc.y+tc.y)/2;
              return (
                <g key={link.id}>
                  <line x1={fc.x} y1={fc.y} x2={tc.x} y2={tc.y} stroke="#94a3b8" strokeWidth="2" strokeDasharray="6,3"/>
                  <circle cx={mx} cy={my} r="8" fill="#fff" stroke="#e5e7eb" strokeWidth="1" style={{ cursor:"pointer", pointerEvents:"all" }} onClick={()=>setLinks(prev=>prev.filter(l=>l.id!==link.id))}/>
                  <text x={mx} y={my+4} textAnchor="middle" fontSize="10" fill="#ef4444" style={{ pointerEvents:"all", cursor:"pointer" }} onClick={()=>setLinks(prev=>prev.filter(l=>l.id!==link.id))}>x</text>
                </g>
              );
            })}
          </svg>

          {devices.map(dev => {
            const info = DEVICE_TYPES[dev.type];
            const isSel = selected === dev.id;
            return (
              <div key={dev.id} style={{ position:"absolute", left:dev.x, top:dev.y, width:80, userSelect:"none" }}
                onMouseDown={e=>handleMouseDown(e,dev)}
                onDoubleClick={()=>{ if(tool==="select") setConfigDevice(dev); }}>
                <div style={{ width:80, height:80, background:info.bg, border:`2px solid ${isSel?info.color:"#e5e7eb"}`, borderRadius:12, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:4, boxShadow:isSel?`0 0 0 3px ${info.color}33`:"0 2px 8px #00000015", cursor:tool==="select"?"grab":"default", transition:"all 0.1s" }}>
                  <DevIcon type={dev.type} size={28} />
                </div>
                <div style={{ textAlign:"center", fontSize:10, fontWeight:700, color:"#374151", marginTop:4, whiteSpace:"nowrap" }}>{dev.name}</div>
                <div style={{ textAlign:"center", fontSize:9, color:"#9ca3af", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis", maxWidth:80 }}>{dev.model}</div>
                {isSel && tool==="select" && (
                  <div style={{ display:"flex", justifyContent:"center", gap:4, marginTop:4 }}>
                    <button onClick={e=>{e.stopPropagation();setConfigDevice(dev);}} style={{ background:info.color, border:"none", color:"#fff", fontSize:9, padding:"2px 6px", borderRadius:4, cursor:"pointer", fontWeight:700 }}>Config</button>
                    <button onClick={e=>{e.stopPropagation();setTermDevice(dev);}} style={{ background:"#0f172a", border:"none", color:"#10b981", fontSize:9, padding:"2px 6px", borderRadius:4, cursor:"pointer", fontWeight:700, fontFamily:"monospace" }}>Term</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* RIGHT PANEL — DEVICE BROWSER */}
        <div style={{ width:200, background:"#fff", borderLeft:"1px solid #e5e7eb", overflowY:"auto", padding:"10px" }}>
          <div style={{ fontSize:10, color:"#9ca3af", textTransform:"uppercase", letterSpacing:1, marginBottom:10 }}>Device Library</div>
          {Object.entries(DEVICE_TYPES).map(([type, info]) => (
            <div key={type} style={{ marginBottom:14 }}>
              <div style={{ fontSize:10, fontWeight:700, color:info.color, marginBottom:6, display:"flex", alignItems:"center", gap:5 }}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
                {info.label}
              </div>
              {info.models.map((model, i) => (
                <button key={i} onClick={()=>addDevice(type, model)} style={{ width:"100%", background:"#f8fafc", border:"1px solid #e5e7eb", borderRadius:6, padding:"6px 8px", cursor:"pointer", textAlign:"left", marginBottom:3, transition:"all 0.1s" }}
                  onMouseEnter={e=>{ e.currentTarget.style.background=`${info.color}10`; e.currentTarget.style.borderColor=info.color; }}
                  onMouseLeave={e=>{ e.currentTarget.style.background="#f8fafc"; e.currentTarget.style.borderColor="#e5e7eb"; }}>
                  <div style={{ fontSize:10, fontWeight:700, color:"#111827" }}>{model.name}</div>
                  <div style={{ fontSize:9, color:"#9ca3af", marginTop:1 }}>{model.ports}</div>
                </button>
              ))}
            </div>
          ))}
        </div>
      </div>

      {configDevice && <ConfigPanel device={configDevice} onClose={()=>setConfigDevice(null)} />}
      {termDevice && <DeviceTerminal device={termDevice} onClose={()=>setTermDevice(null)} />}
    </div>
  );
};

// ═══ MAIN GUI ═══
export default function GUI({ onCommand }) {
  return <Topology />;
}
